import React, { useState, useRef, useEffect } from "react";
import "./App.css";

function App() {
  const [message, setMessage] = useState("");
  const [chat, setChat] = useState([]);
  const chatEndRef = useRef(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [chat]);

  const sendMessage = async () => {
    if (!message) return;

    const userMsg = { role: "user", text: message };
    setChat((prev) => [...prev, userMsg]);

    const res = await fetch("http://localhost:8000/chat", {
      method: "POST",
      headers: {"Content-Type": "application/json"},
      body: JSON.stringify({ message })
    });

    const data = await res.json();

    setChat((prev) => [
      ...prev,
      { role: "bot", text: data.answer, sources: data.sources }
    ]);

    setMessage("");
  };

  return (
    <div className="app">

      {/* ✅ Sidebar (ONLY ONE) */}
      <div className="sidebar">

        {/* Nike Logo */}
        <div className="nike-logo">
          <img src="/nike.png" alt="Nike-Logo" />
        </div>

        {/* Bot Name */}
        <div className="brand">
          <h2>NikeBot</h2>
          <span>AI Assistant</span>
        </div>

        <button className="new-chat">+ New Chat</button>

        <div className="recent">
          <h4>Recent Chats</h4>
          <div className="chat-item">Project overview</div>
          <div className="chat-item">Architecture</div>
        </div>

      </div>

      {/* ✅ Main */}
      <div className="main">

        {/* Topbar */}
        <div className="topbar">
          <h3>AI Assistant</h3>

          <div className="right-section">
            <img src="/quadrant.png" alt="Quadrant-Logo" />
            <span className="status">● Online</span>
          </div>
        </div>

        {/* Chat Area */}
        <div className="chat-area">
          {chat.map((c, i) => (
            <div key={i} className={`msg ${c.role}`}>
              <div className="bubble">
                {c.text}

                {c.sources && (
                  <div className="sources">
                    {c.sources.map((s, idx) => (
                      <a key={idx} href="#" target="_blank" rel="noreferrer">
                        {s}
                      </a>
                    ))}
                  </div>
                )}
              </div>
            </div>
          ))}
          <div ref={chatEndRef}></div>
        </div>

        {/* Input */}
        <div className="input-box">
          <button className="mic">🎤</button>

          <input
            value={message}
            onChange={(e) => setMessage(e.target.value)}
            placeholder="Type your message..."
          />

          <button className="send" onClick={sendMessage}>➤</button>
        </div>

      </div>
    </div>
  );
}

export default App;
